INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000000', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'text', '{"html":"<h3>Why the Math Matters</h3><p>Surveying is applied geometry. Every distance, angle, area, and coordinate you compute rests on a small toolkit of algebra and geometry that you will use thousands of times in a career. Before reaching trigonometry and coordinate geometry, you must be fluent in the basics: rearranging equations, working with the Pythagorean theorem, and reasoning about triangles, circles, and polygons. The goal of this lesson is fluency, not novelty. A surveyor who hesitates over <em>solving for x</em> in the field will be slow and error-prone; a surveyor who has automated these operations can focus attention on the survey itself.</p><p>Throughout this module we treat math as a <strong>tool for decisions</strong>. A number is never the end product; it supports a boundary, a stakeout, or an area report. Carry enough significant figures through intermediate steps, and round only at the end.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000001', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'text', '{"html":"<h3>Solving Equations</h3><p>The core algebra skill is isolating an unknown. A linear equation such as <em>D = R x T</em> can be solved for any of its variables by performing the same operation on both sides. If you know the slope distance and the slope, you solve for horizontal distance; if you know an area and a width, you solve for length. The rules never change:</p><ul><li><strong>Whatever you do to one side, do to the other</strong> (add, subtract, multiply, divide).</li><li>Undo operations in reverse order (addition before multiplication when isolating).</li><li>Keep units attached so a final answer is dimensionally sensible (feet, not feet-squared, for a distance).</li></ul><p>Quadratic relationships also appear, most often through the Pythagorean theorem, where a squared term must be undone by a square root. Knowing which root (positive distance) is physically meaningful is part of the skill.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000002', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'equation', '{"latex":"a^2 + b^2 = c^2 \\quad\\Longrightarrow\\quad c = \\sqrt{a^2 + b^2}","label":"Pythagorean theorem (right triangle)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000003', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'text', '{"html":"<h3>Geometry You Will Use Daily</h3><p>A handful of geometric facts underlie most survey computations:</p><ul><li><strong>Triangles:</strong> the three interior angles sum to 180 degrees; the right triangle (one 90-degree angle) is the workhorse of survey math.</li><li><strong>Circles:</strong> circumference is <em>2&pi;r</em> and area is <em>&pi;r&sup2;</em>; arc length and curve geometry derive from these and drive every roadway curve.</li><li><strong>Polygons:</strong> the interior angles of a closed n-sided figure sum to <em>(n - 2) x 180 degrees</em>. This is the foundation of the <strong>angular closure check</strong> on a traverse: the measured interior angles of a closed polygon must total this value, and the small difference is the angular misclosure.</li></ul><p>Memorize the polygon angle-sum rule. For a five-sided tract the interior angles should total 540 degrees; if your field angles sum to 540 degrees 02 minutes, you have 2 minutes of angular misclosure to distribute.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000004', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'table', '{"headers":["Sides (n)","Shape","Sum of interior angles"],"rows":[["3","Triangle","180 degrees"],["4","Quadrilateral","360 degrees"],["5","Pentagon","540 degrees"],["6","Hexagon","720 degrees"],["8","Octagon","1080 degrees"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000005', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'text', '{"html":"<h3>Ratios, Proportions, and Similar Triangles</h3><p>A <strong>proportion</strong> sets two ratios equal, a/b = c/d, and lets you solve for any one unknown by cross-multiplication. Proportions are everywhere in surveying: converting map distance to ground distance at a stated scale, apportioning excess or deficiency among lots, and reducing slope to horizontal.</p><p><strong>Similar triangles</strong> are the geometric engine behind this. Two triangles are similar when their corresponding angles are equal; their corresponding sides are then proportional. Stadia tacheometry, shadow-and-staff height estimation, and offset computations all exploit similarity. If a 12-ft pole casts a 5-ft shadow at the same instant a tree casts a 40-ft shadow, the tree height solves by the proportion 12/5 = h/40, giving h = 96 ft. The discipline is recognizing the similar triangles hiding inside a field problem.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000006', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Similar triangles share equal angles, so corresponding sides are proportional, the basis of scaling and stadia."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0001-0000-0000-000000000007', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'key_takeaways', '{"title":"Key Takeaways","items":["Solve equations by doing the same operation to both sides; keep units attached.","The Pythagorean theorem links the legs and hypotenuse of every right triangle.","Interior angles of an n-sided polygon sum to (n - 2) x 180 degrees, the angular closure check.","Proportions and similar triangles scale measurements and underlie stadia and apportionment."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000000', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'text', '{"html":"<h3>Trigonometry Is the Language of Surveying</h3><p>Surveying measures <strong>angles and distances</strong> and converts them into <strong>positions</strong>. Trigonometry is the bridge. A total station reads a horizontal angle and a distance; turning that into a northing and easting requires sine and cosine. Reducing a slope distance to horizontal requires cosine. Computing a missing side of a triangulated tract requires the law of sines or cosines. You cannot do survey computations without trigonometry, so it must become second nature.</p><p>The three primary functions, sine, cosine, and tangent, are defined first from the right triangle and then generalized to all angles by the unit circle, which is what lets us handle bearings and azimuths in any direction.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000001', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'text', '{"html":"<h3>The Right-Triangle Definitions: SOHCAHTOA</h3><p>For an acute angle <em>&theta;</em> in a right triangle, label the sides relative to that angle: the <strong>opposite</strong> side, the <strong>adjacent</strong> side, and the <strong>hypotenuse</strong> (always the side opposite the 90-degree angle). The mnemonic <strong>SOHCAHTOA</strong> encodes the three ratios:</p><ul><li><strong>S</strong>ine = <strong>O</strong>pposite / <strong>H</strong>ypotenuse</li><li><strong>C</strong>osine = <strong>A</strong>djacent / <strong>H</strong>ypotenuse</li><li><strong>T</strong>angent = <strong>O</strong>pposite / <strong>A</strong>djacent</li></ul><p>The inverse functions (arcsin, arccos, arctan) go the other way: given a ratio of sides, they return the angle. In coordinate geometry the two-argument arctangent, <em>atan2(dE, dN)</em>, returns the azimuth directly and is preferred because it resolves the correct quadrant automatically.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'equation', '{"latex":"\\sin\\theta=\\frac{\\text{opp}}{\\text{hyp}},\\qquad \\cos\\theta=\\frac{\\text{adj}}{\\text{hyp}},\\qquad \\tan\\theta=\\frac{\\text{opp}}{\\text{adj}}=\\frac{\\sin\\theta}{\\cos\\theta}","label":"Right-triangle trigonometric ratios","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000003', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'text', '{"html":"<h3>The Unit Circle</h3><p>The right-triangle definitions only cover angles between 0 and 90 degrees, but surveyors work in all four directions. The <strong>unit circle</strong> (radius 1, centered at the origin) extends the definitions to any angle. A point on the circle at angle <em>&theta;</em>, measured counterclockwise from the positive x-axis, has coordinates <strong>(cos &theta;, sin &theta;)</strong>. As <em>&theta;</em> sweeps around, sine and cosine take on positive and negative values depending on the quadrant, which is exactly what we need to compute departures (east-west) and latitudes (north-south) for any bearing.</p><p>Note the surveyor''s twist: surveyors measure <strong>azimuths clockwise from north</strong>, not counterclockwise from east. So in survey work the latitude (north) component uses cosine of the azimuth and the departure (east) component uses sine of the azimuth, the reverse of the math-class convention. Keep this straight and the signs fall out correctly by quadrant.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000004', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'table', '{"headers":["Quadrant","Azimuth range","Latitude (cos Az)","Departure (sin Az)"],"rows":[["NE (I)","0 to 90 degrees","+","+"],["SE (II)","90 to 180 degrees","-","+"],["SW (III)","180 to 270 degrees","-","-"],["NW (IV)","270 to 360 degrees","+","-"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000005', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'text', '{"html":"<h3>Degrees, DMS, and Radians</h3><p>Survey instruments report angles in <strong>degrees, minutes, and seconds (DMS)</strong>: 1 degree = 60 minutes, 1 minute = 60 seconds. To compute with a calculator you usually convert DMS to <strong>decimal degrees</strong> first (decimal = D + M/60 + S/3600), then convert to <strong>radians</strong> if a function library expects them, because computers evaluate trig functions in radians. The conversion is radians = degrees x &pi;/180. Always confirm whether your engine wants degrees or radians; a missing toRad() conversion is one of the most common causes of a nonsense answer.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000006', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'equation', '{"latex":"\\sin^2\\theta + \\cos^2\\theta = 1,\\qquad 1+\\tan^2\\theta=\\sec^2\\theta,\\qquad \\text{rad}=\\text{deg}\\times\\frac{\\pi}{180}","label":"Pythagorean identity and degree-radian conversion","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000007', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'accordion', '{"sections":[{"title":"Why the identities matter in practice","content":"<p>The master identity <strong>sin&sup2;&theta; + cos&sup2;&theta; = 1</strong> is more than a textbook fact. It lets you recover one function from another without re-measuring an angle, and it gives a quick sanity check: a computed latitude and departure for a line of length L must satisfy lat&sup2; + dep&sup2; = L&sup2;, which is just the identity scaled by L. If that does not hold, you made an arithmetic error.</p>","open":false}]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0002-0000-0000-000000000008', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'key_takeaways', '{"title":"Key Takeaways","items":["SOHCAHTOA defines sine, cosine, and tangent from a right triangle''s sides.","The unit circle extends these to all angles; signs change by quadrant.","In survey convention, latitude = L cos(Az) and departure = L sin(Az), with azimuth clockwise from north.","Convert DMS to decimal degrees, then to radians for computation (rad = deg x pi/180).","sin^2 + cos^2 = 1 recovers one function from another and checks lat/dep work."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000000', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'text', '{"html":"<h3>The Surveyor''s Most-Used Triangle</h3><p>The right triangle appears in nearly every routine survey computation: reducing slope distances to horizontal, computing the rise or fall of a line, locating a point by a perpendicular offset, and finding the straight-line distance between two stations. Because one angle is fixed at 90 degrees, a right triangle is fully determined by just two more pieces of data, either one side and one acute angle, or any two sides. Master the right triangle and a large fraction of field math becomes routine.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000001', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'text', '{"html":"<h3>Slope Reduction to Horizontal and Vertical</h3><p>An EDM or total station measures the <strong>slope distance</strong> along the line of sight, but maps, areas, and coordinates require the <strong>horizontal distance</strong>. The slope distance is the hypotenuse of a right triangle whose horizontal leg is the horizontal distance and whose vertical leg is the elevation difference. If the instrument reports the <strong>vertical angle</strong> <em>&alpha;</em> above horizontal (or you convert a zenith angle z by &alpha; = 90 - z), then:</p><ul><li>Horizontal distance H = S x cos(&alpha;)</li><li>Vertical difference V = S x sin(&alpha;)</li></ul><p>For a sight that is nearly level, cos(&alpha;) is close to 1 and the horizontal distance is almost the full slope distance; for steep terrain the correction is large and must never be skipped.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'equation', '{"latex":"H = S\\cos\\alpha,\\qquad V = S\\sin\\alpha,\\qquad S=\\sqrt{H^2+V^2}","label":"Slope reduction with vertical angle alpha","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000003', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'text', '{"html":"<h3>Finding a Missing Side: The Pythagorean Workhorse</h3><p>When you know two sides of a right triangle, the third follows directly from the Pythagorean theorem. To find the hypotenuse from two legs, c = sqrt(a&sup2; + b&sup2;). To find a missing leg from the hypotenuse and the other leg, b = sqrt(c&sup2; - a&sup2;). This is the basis of the straight-line (radial) distance between two coordinates and of countless offset and tie computations. In code the helper <em>hypot(a, b)</em> computes sqrt(a&sup2; + b&sup2;) in one step and avoids overflow, which is why it appears throughout coordinate geometry.</p><p>Always confirm the answer is physically sensible. A computed leg must be smaller than the hypotenuse; a computed hypotenuse must be larger than either leg. If not, you have mixed up which side is which.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000004', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'callout', '{"type":"info","text":"Tip: when reducing slope to horizontal, double-check whether your instrument gives a vertical angle (measured from horizontal) or a zenith angle (measured from straight up). They are complements: vertical angle = 90 degrees - zenith angle. Using the wrong one swaps sine and cosine."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000005', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'text', '{"html":"<h3>Heights and Perpendicular Offsets</h3><p>Right triangles also solve indirect heights and offsets. To find the height of an inaccessible object, measure the horizontal distance D to its base and the vertical angle &alpha; to its top: height = D x tan(&alpha;), plus the instrument height. To locate a feature offset from a line, the perpendicular offset distance and the along-line distance form the legs of a right triangle whose hypotenuse is the radial tie. These same relations let you set a point at a right angle from a baseline using the 3-4-5 rule, a field application of the Pythagorean theorem that needs no instrument at all.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000006', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Slope distance reduced to horizontal (S cos alpha) and vertical (S sin alpha) components."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0003-0000-0000-000000000007', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'key_takeaways', '{"title":"Key Takeaways","items":["A right triangle is solved from one side plus an acute angle, or from any two sides.","Horizontal distance = slope x cos(vertical angle); vertical = slope x sin(vertical angle).","Vertical angle and zenith angle are complements (sum to 90 degrees); do not confuse them.","Missing side from two known sides: hypotenuse = hypot(a, b); leg = sqrt(c^2 - a^2).","Indirect height = horizontal distance x tan(vertical angle) plus instrument height."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000000', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'text', '{"html":"<h3>When the Triangle Has No Right Angle</h3><p>Many survey triangles are <strong>oblique</strong>, that is, none of their angles is 90 degrees. Triangulation networks, intersection and resection computations, and the geometry of a triangulated tract all involve oblique triangles. Two laws solve them: the <strong>law of sines</strong> and the <strong>law of cosines</strong>. Choosing the right one depends on which combination of sides and angles you know.</p><p>Label every triangle with vertices A, B, C and the opposite sides a, b, c, so side a is opposite angle A. Keeping this labeling consistent prevents most errors.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000001', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'text', '{"html":"<h3>The Law of Sines</h3><p>The <strong>law of sines</strong> states that each side is proportional to the sine of its opposite angle. It is the tool when you know two angles and any side (cases ASA and AAS), because the third angle is just 180 degrees minus the other two, and then the proportion gives the remaining sides. It also handles the two-sides-and-a-non-included-angle case (SSA), but that case is <em>ambiguous</em> and must be treated carefully.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'equation', '{"latex":"\\frac{a}{\\sin A}=\\frac{b}{\\sin B}=\\frac{c}{\\sin C}","label":"Law of sines","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000003', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'callout', '{"type":"warning","text":"The ambiguous case (SSA): when you know two sides and an angle opposite one of them, the law of sines may yield zero, one, or TWO valid triangles, because sin(theta) = sin(180 - theta). Always check whether the supplementary angle also produces a geometrically valid triangle (angles must sum to less than 180 degrees) and use field knowledge to pick the right one."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000004', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'text', '{"html":"<h3>The Law of Cosines</h3><p>The <strong>law of cosines</strong> generalizes the Pythagorean theorem to any triangle. Use it in two situations the law of sines cannot start: when you know <strong>two sides and the included angle (SAS)</strong> and need the third side, and when you know <strong>all three sides (SSS)</strong> and need an angle. For the side form, the unknown side opposite the known angle C is:</p><p>This is invaluable when two control points are tied to a third by two measured distances and the angle between them is observed, a common triangulation geometry.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000005', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'equation', '{"latex":"c^2 = a^2 + b^2 - 2ab\\cos C \\quad\\Longrightarrow\\quad \\cos C = \\frac{a^2+b^2-c^2}{2ab}","label":"Law of cosines (side form and angle form)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000006', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'table', '{"headers":["You know","Case","Use"],"rows":[["Two angles + any side","ASA / AAS","Law of sines"],["Two sides + included angle","SAS","Law of cosines (for the side)"],["All three sides","SSS","Law of cosines (for an angle)"],["Two sides + non-included angle","SSA (ambiguous)","Law of sines, check both solutions"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000007', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'text', '{"html":"<h3>A Surveying Application</h3><p>Suppose a surveyor occupies station B and measures the distances to two control points A and C as a = 412.50 ft and c = 380.20 ft, with the included angle at B equal to 73 degrees 15 minutes. The unknown distance b between A and C follows directly from the law of cosines: b&sup2; = a&sup2; + c&sup2; - 2ac cos(B). Once b is known, the law of sines gives the remaining angles, completely fixing the triangle. This SAS-to-everything workflow is the backbone of triangulation and of checking distances that cannot be measured directly because of an obstruction.</p>"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0004-0000-0000-000000000008', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'key_takeaways', '{"title":"Key Takeaways","items":["Oblique triangles (no right angle) are solved with the law of sines or law of cosines.","Law of sines (a/sin A = b/sin B = c/sin C) handles ASA, AAS, and the ambiguous SSA case.","Law of cosines (c^2 = a^2 + b^2 - 2ab cos C) handles SAS for a side and SSS for an angle.","The SSA case can yield zero, one, or two triangles; always check the supplementary angle.","Label sides opposite their angles (a opposite A) to keep computations straight."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000000', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'text', '{"html":"<h3>What COGO Is</h3><p><strong>Coordinate geometry</strong>, universally called <strong>COGO</strong>, is the computation of positions in a plane rectangular system. Every point is stored as a <strong>northing (N or Y)</strong> and an <strong>easting (E or X)</strong>. From those coordinates, and from bearings and distances, COGO answers the everyday questions of surveying: where is a point, how far apart are two points, what is the direction from one to another, and where do two lines or two circles cross. Modern data collectors and CAD do COGO automatically, but the surveyor must understand the underlying trigonometry to set up problems correctly and to catch blunders.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000001', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'text', '{"html":"<h3>The Forward Computation</h3><p>The <strong>forward</strong> problem starts at a known point and a known <strong>azimuth</strong> (direction clockwise from north) and <strong>distance</strong>, and computes the next point. The line''s <strong>departure</strong> (change in easting) and <strong>latitude</strong> (change in northing) are:</p><ul><li>dE = L x sin(Azimuth)</li><li>dN = L x cos(Azimuth)</li></ul><p>The new coordinates are simply N2 = N1 + dN and E2 = E1 + dE. Repeating this around a traverse generates every station''s coordinates. The signs of dE and dN come out automatically from the sine and cosine of the azimuth, which is why working in azimuths (0 to 360 degrees) is cleaner than working in quadrant bearings with manual sign bookkeeping.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'equation', '{"latex":"\\Delta E = L\\sin(\\text{Az}),\\qquad \\Delta N = L\\cos(\\text{Az}),\\qquad N_2=N_1+\\Delta N,\\quad E_2=E_1+\\Delta E","label":"Forward computation (coordinates from azimuth and distance)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000003', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'text', '{"html":"<h3>The Inverse Computation</h3><p>The <strong>inverse</strong> is the reverse and the single most-used COGO operation: given two known points, find the <strong>distance</strong> and <strong>azimuth</strong> between them. Compute the differences dE = E2 - E1 and dN = N2 - N1, then:</p><ul><li>Distance = sqrt(dE&sup2; + dN&sup2;) = hypot(dE, dN), straight from the Pythagorean theorem.</li><li>Azimuth = atan2(dE, dN), the two-argument arctangent, which returns the correct quadrant automatically.</li></ul><p>Because <em>atan2(dE, dN)</em> can return a negative angle, add 360 degrees when the result is negative to express the azimuth in the conventional 0-to-360-degree range. The inverse is how you stake a line between two coordinates, check a measured distance against record, and report a bearing for a deed call.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000004', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'equation', '{"latex":"L=\\sqrt{(\\Delta E)^2+(\\Delta N)^2},\\qquad \\text{Az}=\\operatorname{atan2}(\\Delta E,\\ \\Delta N)\\ (\\text{add }360^\\circ\\text{ if negative})","label":"Inverse computation (distance and azimuth from coordinates)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000005', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'callout', '{"type":"info","text":"Note the argument order for surveyors: azimuth is measured from north, so the easting difference (dE) is the first argument and the northing difference (dN) is the second: atan2(dE, dN). The math-class convention atan2(y, x) measures from the x-axis, so the arguments are swapped relative to standard COGO."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000006', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'text', '{"html":"<h3>Intersections</h3><p>An <strong>intersection</strong> locates a new point as the meeting of two lines of position. The three classic forms are:</p><ul><li><strong>Bearing-bearing:</strong> a known point and azimuth from each of two stations; the new point is where the two lines cross.</li><li><strong>Distance-distance:</strong> a known distance (radius) from each of two stations; the new point is where the two circles cross, generally two solutions, so field context picks the right one.</li><li><strong>Bearing-distance:</strong> a line from one station and a radius from another.</li></ul><p>Intersections are the math behind resection, free-stationing, and locating a corner by ties to two found monuments. Each reduces to solving a small system of equations built from the forward and inverse relations above.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000007', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The inverse between two coordinates. dE and dN form the legs; distance is the hypotenuse and azimuth is atan2(dE, dN)."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0005-0000-0000-000000000008', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'key_takeaways', '{"title":"Key Takeaways","items":["Every COGO point has a northing (Y) and an easting (X).","Forward: dE = L sin(Az), dN = L cos(Az); add to the prior coordinates.","Inverse: distance = hypot(dE, dN), azimuth = atan2(dE, dN) (add 360 if negative).","For survey azimuths, atan2 takes dE first then dN (from north, not from the x-axis).","Intersections locate a point from two bearings, two distances, or a bearing and a distance."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000000', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'text', '{"html":"<h3>Why Units Are a Boundary Issue</h3><p>Unit errors are among the costliest mistakes a surveyor can make, because they silently scale an entire survey. A retracement that treats varas as feet, or a state-plane distance that mixes survey feet with international feet, can be off by enough to start a lawsuit. Surveyors must move fluently among <strong>feet, meters, chains, and varas</strong>, and must know which unit the original record actually used. In Texas this is unavoidable: the oldest grants are dimensioned in <strong>varas</strong>, public-land states used Gunter''s <strong>chains</strong>, and modern geodetic work is in <strong>meters</strong>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000001', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'text', '{"html":"<h3>Chains and Links: The Gunter''s Chain</h3><p>The <strong>Gunter''s chain</strong> was the standard land-measuring unit of early American surveys and is baked into our area units. One chain is <strong>66 feet</strong>, divided into <strong>100 links</strong> (so 1 link = 0.66 ft = 7.92 inches). The genius of the chain is its tie to the acre: an <strong>acre is exactly 10 square chains</strong>, which is 43,560 square feet, and 80 chains make a mile. Many old deeds and all PLSS field notes are in chains and links, so converting chains to feet (multiply by 66) is a routine retracement step, even though Texas itself used varas rather than chains for its sovereign grants.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'table', '{"headers":["From","To","Multiply by"],"rows":[["Chains","Feet","66"],["Links","Feet","0.66"],["Varas (Texas)","Feet","2.77778"],["Meters","U.S. survey feet","3.280833333"],["Feet","Meters (intl)","0.3048"],["Acres","Square feet","43,560"],["Square chains","Acres","0.1"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000003', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'text', '{"html":"<h3>The Vara: The Spanish Surveyor''s Yard</h3><p>The <strong>vara</strong> is the Spanish unit of length that dimensions nearly every Spanish, Mexican, and Republic-of-Texas land grant. Its length varied historically by region, which is exactly why surveyors must use the locally adopted value. <strong>Texas adopted a legal vara of 33&nbsp;1/3 inches</strong>, which is exactly 2.7778 feet (so 36 varas = 100 feet). Many original Texas grants are 1000 varas, 1900 varas, or one labor (1000 varas square) on a side. When retracing such a grant you convert the record varas to feet at the Texas value, run the geometry in feet, then compare to found monuments. Using a different region''s vara, or treating varas as yards, introduces a systematic scale error across the whole tract.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000004', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'callout', '{"type":"warning","text":"Texas differs: The legal Texas vara is exactly 33 1/3 inches = 2.7778 feet. This is the value to use when retracing Spanish, Mexican, and Republic-of-Texas grants and when reading old GLO field notes that call distances in varas. Do not assume the vara value of another former Spanish jurisdiction (California and Florida used slightly different values)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000005', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'text', '{"html":"<h3>The U.S. Survey Foot vs. the International Foot</h3><p>There are two definitions of the foot in use, and they differ. The <strong>international foot</strong> is exactly 0.3048 meters. The <strong>U.S. survey foot</strong> is defined as 1200/3937 meters, about 0.30480061 meters, making it longer than the international foot by roughly <strong>2 parts per million</strong>. Over a short distance the difference is negligible, but over a State Plane Coordinate System coordinate of several hundred thousand feet it amounts to a foot or more, which is unacceptable in control work. The U.S. survey foot was historically used for State Plane Coordinates; the international foot is the modern default and the U.S. survey foot is being phased out. Always know and document which foot your coordinates use.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0006-0000-0000-000000000006', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'key_takeaways', '{"title":"Key Takeaways","items":["1 chain = 66 ft = 100 links; 1 acre = 43,560 sq ft = 10 square chains; 80 chains = 1 mile.","Texas legal vara = 33 1/3 inches = 2.7778 ft (36 varas = 100 ft); use it for Spanish/Mexican/Republic grants.","U.S. survey foot = 1200/3937 m, longer than the international foot (0.3048 m) by ~2 ppm.","Unit errors scale an entire survey; always document which unit and which foot a coordinate uses."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000000', '392e4287-7043-44e7-8bc0-b81d423c933b', 'text', '{"html":"<h3>Three Families of Area Methods</h3><p>Computing the area of a parcel is one of the surveyor''s defining deliverables, the acreage that appears on a plat and in a deed. There are three families of methods, chosen by what data you have: <strong>triangle formulas</strong> when the tract can be broken into triangles, the <strong>trapezoidal (and Simpson''s) rule</strong> when one boundary is an irregular curve sampled by offsets, and the <strong>coordinate (shoelace) method</strong> when every corner has a known northing and easting. The coordinate method is the modern default because traverse computations already produce coordinates for every corner.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000001', '392e4287-7043-44e7-8bc0-b81d423c933b', 'text', '{"html":"<h3>Triangle Areas</h3><p>The triangle is the atom of area computation, since any polygon can be triangulated. Three formulas cover the common data sets:</p><ul><li><strong>Base and height:</strong> A = 1/2 x base x height, when an altitude is known.</li><li><strong>Two sides and the included angle (SAS):</strong> A = 1/2 x a x b x sin(C), the most useful field form.</li><li><strong>Three sides (SSS), Heron''s formula:</strong> with semiperimeter s = (a + b + c)/2, A = sqrt(s(s - a)(s - b)(s - c)).</li></ul><p>The SAS form pairs naturally with the law of cosines from the oblique-triangle lesson: measure two sides and the angle between them, get the area immediately, or get the third side and then use Heron''s formula.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', 'equation', '{"latex":"A=\\tfrac{1}{2}ab\\sin C,\\qquad A=\\sqrt{s(s-a)(s-b)(s-c)},\\ \\ s=\\tfrac{a+b+c}{2}","label":"Triangle area: SAS form and Heron''s formula","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000003', '392e4287-7043-44e7-8bc0-b81d423c933b', 'text', '{"html":"<h3>Irregular Boundaries: The Trapezoidal Rule</h3><p>When one edge of a tract is an irregular line, a stream bank or a winding road, surveyors run a straight baseline and measure perpendicular <strong>offsets</strong> to the boundary at regular intervals of spacing <em>h</em>. The area of each strip is approximated as a trapezoid (the average of its two end offsets times the spacing). Summing the strips gives the <strong>trapezoidal rule</strong>. For smoother results with curved boundaries, <strong>Simpson''s one-third rule</strong> fits parabolas through groups of three offsets and is more accurate when the number of intervals is even.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000004', '392e4287-7043-44e7-8bc0-b81d423c933b', 'equation', '{"latex":"A \\approx h\\left(\\frac{o_0+o_n}{2}+o_1+o_2+\\cdots+o_{n-1}\\right)","label":"Trapezoidal rule (offsets o spaced h apart)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000005', '392e4287-7043-44e7-8bc0-b81d423c933b', 'text', '{"html":"<h3>The Coordinate (Shoelace) Method</h3><p>When every corner of a closed polygon has coordinates, area follows directly from the <strong>shoelace formula</strong> (the cross-product or surveyor''s-area method), which is the practical equivalent of the <strong>double-meridian-distance (DMD)</strong> technique. List the vertices in order around the boundary and sum the cross products of consecutive coordinates; half the absolute value of that sum is the area:</p><p>The result is in square units of the coordinates (square feet), so divide by 43,560 to report acres. The method is exact for any simple polygon, never needs the figure to be subdivided, and is what every CAD and data collector uses internally. A sign convention note: a positive sum means the vertices were listed counterclockwise and a negative sum clockwise, so taking the absolute value gives the area either way.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000006', '392e4287-7043-44e7-8bc0-b81d423c933b', 'equation', '{"latex":"A=\\frac{1}{2}\\left|\\sum_{i=1}^{n}\\bigl(X_i\\,Y_{i+1}-X_{i+1}\\,Y_i\\bigr)\\right|\\qquad(\\text{indices wrap: }n+1\\to 1)","label":"Shoelace (coordinate) area formula","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000007', '392e4287-7043-44e7-8bc0-b81d423c933b', 'table', '{"headers":["Data you have","Best area method"],"rows":[["Base and altitude of a triangle","A = 1/2 base x height"],["Two sides and included angle","A = 1/2 ab sin(C)"],["All three sides","Heron''s formula"],["Offsets to an irregular boundary","Trapezoidal or Simpson''s rule"],["Coordinates of every corner","Shoelace / DMD method"]]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000008', '392e4287-7043-44e7-8bc0-b81d423c933b', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The shoelace method cross-multiplies consecutive coordinate pairs around the polygon; half the absolute sum is the area."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0007-0000-0000-000000000009', '392e4287-7043-44e7-8bc0-b81d423c933b', 'key_takeaways', '{"title":"Key Takeaways","items":["Triangle area: 1/2 base x height, 1/2 ab sin(C), or Heron''s sqrt(s(s-a)(s-b)(s-c)).","The trapezoidal rule averages end offsets of each strip; Simpson''s rule is more accurate for curves.","The shoelace formula gives any polygon''s area directly from its coordinates and equals the DMD method.","Coordinate area comes out in square feet; divide by 43,560 for acres.","Take the absolute value in the shoelace formula so the sign of the vertex order does not matter."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0008-0000-0000-000000000000', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'text', '{"html":"<h3>Putting the Toolkit Together</h3><p>Field math is rarely a single formula. A typical problem chains several steps: reduce slope distances to horizontal, run the forward computation to get coordinates, inverse between two corners to check a record distance, then compute the enclosed area and convert to acres. This lesson is about <strong>workflow and judgment</strong>, choosing which tool applies, sequencing the steps, and managing precision so the final number is trustworthy. The accompanying problem templates let you practice each core computation with randomized values.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0008-0000-0000-000000000001', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'text', '{"html":"<h3>A Worked Multi-Step Example</h3><p>Two found monuments have coordinates A(N 5000.00, E 5000.00) and B(N 5210.40, E 5318.75), and a third corner C(N 4880.10, E 5295.60) was set by ties. To report the triangle''s acreage:</p><ul><li><strong>Inverse A to B:</strong> dE = 318.75, dN = 210.40, so distance = hypot(318.75, 210.40) = 381.92 ft and azimuth = atan2(318.75, 210.40) = 56 degrees 33 minutes.</li><li><strong>Area by shoelace</strong> from the three coordinates gives the square footage directly.</li><li><strong>Convert:</strong> divide square feet by 43,560 for acres.</li></ul><p>Each step uses a tool from an earlier lesson; the skill is assembling them in order and never rounding until the final acreage.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0008-0000-0000-000000000002', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'callout', '{"type":"info","text":"Precision discipline: carry at least one or two more significant figures through intermediate computations than you intend to report. Distances are typically reported to 0.01 ft, angles to the nearest second, and parcel areas to 0.001 acre or the nearest square foot, but the intermediate trig values should keep full calculator precision."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0008-0000-0000-000000000003', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'text', '{"html":"<h3>A Checklist for Any Field Computation</h3><p>Before computing, inventory the problem:</p><ul><li><strong>What units</strong> are the data in (feet, varas, meters, chains)? Convert to a single working unit first.</li><li><strong>What do I know</strong>, sides, angles, coordinates? That choice selects right-triangle, law of sines/cosines, or COGO.</li><li><strong>Is the triangle right or oblique?</strong> A right angle unlocks SOHCAHTOA; otherwise reach for the sine or cosine law.</li><li><strong>Does the answer pass a sanity check?</strong> A leg shorter than the hypotenuse, an area roughly matching a sketch, an azimuth in the expected quadrant.</li></ul><p>This habit catches the great majority of blunders before they reach a plat.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0008-0000-0000-000000000004', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'table', '{"headers":["Field question","Tool to reach for"],"rows":[["Reduce a slope distance to horizontal","H = S cos(vertical angle)"],["Find the third side of a triangle (SAS)","Law of cosines"],["Distance and bearing between two points","Inverse: hypot and atan2"],["Area of a coordinate polygon","Shoelace formula, then / 43,560"],["Old grant dimensioned in varas","Multiply varas by 2.7778 to get feet"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0210-0008-0000-0000-000000000005', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'key_takeaways', '{"title":"Key Takeaways","items":["Field problems chain tools: convert units, reduce, inverse, compute area, then convert again.","Inventory what is known (sides, angles, coordinates) to pick the right formula.","Keep full precision through intermediate steps and round only the reported answer.","Always run a sanity check: leg < hypotenuse, area near the sketch, azimuth in the right quadrant."]}'::jsonb, 5);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000001', 'Pythagorean theorem', 'For a right triangle with legs a and b and hypotenuse c, a^2 + b^2 = c^2. Used constantly to find a missing side or the straight-line distance between two points.', 'Sum of the squares of the legs.', 'c1000002-0000-0000-0000-000000000002', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000002', 'Polygon angle-sum rule', 'The interior angles of a simple n-sided polygon sum to (n - 2) x 180 degrees. A traverse''s measured interior angles are checked against this total to find angular misclosure.', NULL, 'c1000002-0000-0000-0000-000000000002', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000003', 'Similar triangles', 'Triangles with equal corresponding angles. Their corresponding sides are proportional, which is the basis of scaling, stadia, and offset computations.', NULL, 'c1000002-0000-0000-0000-000000000002', '02ce6947-ebfd-40ed-8ee9-30aae4331968', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000004', 'SOHCAHTOA', 'Mnemonic for the right-triangle ratios: Sine = Opposite/Hypotenuse, Cosine = Adjacent/Hypotenuse, Tangent = Opposite/Adjacent.', NULL, 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000005', 'Unit circle', 'A circle of radius 1 centered at the origin. A point at angle theta has coordinates (cos theta, sin theta), extending the trig functions to all angles and all four quadrants.', NULL, 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000006', 'Pythagorean identity', 'sin^2(theta) + cos^2(theta) = 1. Lets you find one function from another and provides a check that latitude^2 + departure^2 = length^2.', NULL, 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000007', 'DMS to decimal degrees', 'Convert degrees-minutes-seconds to a decimal: decimal = D + M/60 + S/3600. Then multiply by pi/180 to get radians for computation.', '60 minutes per degree, 60 seconds per minute.', 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000008', 'Slope reduction', 'Converting a measured slope (line-of-sight) distance S to horizontal distance using the vertical angle alpha: H = S cos(alpha). The vertical difference is V = S sin(alpha).', NULL, 'c1000002-0000-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000009', 'Zenith vs. vertical angle', 'A zenith angle is measured from straight up (0 to 180 degrees); a vertical angle is measured from horizontal. They are complements: vertical angle = 90 degrees - zenith angle.', 'They sum to 90 degrees.', 'c1000002-0000-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000010', '3-4-5 rule', 'A field application of the Pythagorean theorem: a triangle with sides 3, 4, and 5 (or any multiple) contains a right angle, used to set or check a 90-degree corner without an instrument.', NULL, 'c1000002-0000-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000011', 'Law of sines', 'In any triangle, a/sin A = b/sin B = c/sin C. Used to solve ASA, AAS, and the ambiguous SSA cases.', NULL, 'c1000002-0000-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000012', 'Law of cosines', 'c^2 = a^2 + b^2 - 2ab cos C, a generalization of the Pythagorean theorem. Used for SAS (find the third side) and SSS (find an angle: cos C = (a^2 + b^2 - c^2)/(2ab)).', NULL, 'c1000002-0000-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000013', 'Ambiguous case (SSA)', 'When two sides and a non-included angle are known, the law of sines can produce two valid triangles because sin(theta) = sin(180 - theta). Both must be checked for geometric validity.', 'Two sides and an angle opposite one of them.', 'c1000002-0000-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000014', 'Departure and latitude', 'For a line of length L at azimuth Az, the departure (change in easting) is L sin(Az) and the latitude (change in northing) is L cos(Az). Added to the start point''s coordinates, they give the next point.', NULL, 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000015', 'Inverse (COGO)', 'Computing the distance and azimuth between two known coordinates: distance = hypot(dE, dN); azimuth = atan2(dE, dN), adding 360 degrees if the result is negative.', NULL, 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000016', 'atan2', 'The two-argument arctangent that returns an angle in the correct quadrant. For survey azimuths from north, it is called as atan2(dE, dN).', 'Resolves quadrant automatically.', 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000017', 'Intersection', 'Locating a new point as the meeting of two lines of position: bearing-bearing, distance-distance (two solutions), or bearing-distance. The basis of resection and corner ties.', NULL, 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000018', 'Gunter''s chain', 'A land-measuring unit equal to 66 feet, divided into 100 links. An acre equals 10 square chains (43,560 sq ft) and a mile is 80 chains.', NULL, 'c1000002-0000-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000019', 'Vara (Texas)', 'The Spanish unit of length used in Texas land grants. The legal Texas vara is 33 1/3 inches = 2.7778 feet, so 36 varas equal 100 feet.', 'Used to retrace Spanish, Mexican, and Republic grants.', 'c1000002-0000-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000020', 'U.S. survey foot vs. international foot', 'The international foot is exactly 0.3048 m; the U.S. survey foot is 1200/3937 m (~0.30480061 m), about 2 ppm longer. The difference matters over long state-plane distances.', NULL, 'c1000002-0000-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000021', 'Heron''s formula', 'Area of a triangle from its three sides: with s = (a+b+c)/2, A = sqrt(s(s-a)(s-b)(s-c)). Useful when only side lengths are known.', NULL, 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000022', 'Trapezoidal rule', 'An area method for an irregular boundary sampled by perpendicular offsets at equal spacing h: A = h x ((o0 + on)/2 + o1 + ... + o(n-1)). Each strip is treated as a trapezoid.', NULL, 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000023', 'Shoelace (coordinate) formula', 'Area of a polygon from its vertex coordinates: A = 1/2 |sum of (Xi*Y(i+1) - X(i+1)*Yi)|. Equivalent to the double-meridian-distance method and exact for any simple polygon.', 'Cross-multiply consecutive coordinates.', 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000024', 'Square feet to acres', 'Coordinate and triangle areas come out in square feet. Divide by 43,560 to convert to acres (1 acre = 43,560 sq ft = 10 square chains).', NULL, 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000025', 'Computation workflow', 'The standard field sequence: convert all data to one unit, reduce slope to horizontal, run forward/inverse COGO, compute area, then convert to the reported unit. Round only at the end.', NULL, 'c1000002-0000-0000-0000-000000000002', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0240-0000-0000-0000-000000000026', 'Sanity check', 'A quick reasonableness test on a result: a triangle leg must be shorter than the hypotenuse, a computed area should roughly match a scaled sketch, and an azimuth should fall in the expected quadrant.', NULL, 'c1000002-0000-0000-0000-000000000002', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', 'surveying', ARRAY['buildout','module-2']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000001', 'The interior angles of a closed five-sided traverse should sum to what value, the basis of the angular closure check?', 'multiple_choice', '["360 degrees","540 degrees","720 degrees","900 degrees"]'::jsonb, '540 degrees', 'For an n-sided polygon the interior angles sum to (n - 2) x 180 degrees. For n = 5 that is 3 x 180 = 540 degrees. The small difference between this and the measured total is the angular misclosure.', 'easy', 'c1000002-0000-0000-0000-000000000002', '02ce6947-ebfd-40ed-8ee9-30aae4331968', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000002', 'A 12-ft pole casts a 5-ft shadow at the same moment a flagpole casts a 35-ft shadow. Using similar triangles, how tall is the flagpole?', 'numeric_input', '[]'::jsonb, '84', 'Similar triangles give the proportion 12/5 = h/35, so h = 35 x 12/5 = 84 ft. The equal sun angle makes the triangles similar, so corresponding sides are proportional.', 'medium', 'c1000002-0000-0000-0000-000000000002', '02ce6947-ebfd-40ed-8ee9-30aae4331968', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000003', 'In SOHCAHTOA, the tangent of an acute angle in a right triangle equals which ratio?', 'multiple_choice', '["Opposite / hypotenuse","Adjacent / hypotenuse","Opposite / adjacent","Hypotenuse / opposite"]'::jsonb, 'Opposite / adjacent', 'Tangent = Opposite/Adjacent (the TOA in SOHCAHTOA), which also equals sin/cos. Opposite/hypotenuse is sine and adjacent/hypotenuse is cosine.', 'easy', 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000004', 'Most computer trigonometric function libraries expect angle arguments in radians, not degrees.', 'true_false', '["True","False"]'::jsonb, 'True', 'Computers evaluate trig functions in radians, so a degree value must be converted with toRad (radians = degrees x pi/180) before calling sin, cos, or tan. A missing conversion is a common source of nonsense answers.', 'easy', 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000005', 'Convert the angle 42 degrees 30 minutes 00 seconds to decimal degrees.', 'numeric_input', '[]'::jsonb, '42.5', 'Decimal degrees = D + M/60 + S/3600 = 42 + 30/60 + 0/3600 = 42 + 0.5 = 42.5 degrees.', 'easy', 'c1000002-0000-0000-0000-000000000002', '24f0890d-d4b8-4d6c-b287-009d76f7502d', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000006', 'A total station measures a slope distance of 200.00 ft with a vertical angle of 30 degrees above horizontal. What is the horizontal distance?', 'multiple_choice', '["100.00 ft","173.21 ft","200.00 ft","230.94 ft"]'::jsonb, '173.21 ft', 'Horizontal distance = slope x cos(vertical angle) = 200.00 x cos(30 degrees) = 200.00 x 0.86603 = 173.21 ft. Multiplying by sine instead would give the vertical difference (100.00 ft).', 'medium', 'c1000002-0000-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000007', 'An instrument reports a zenith angle of 85 degrees. What is the equivalent vertical angle above horizontal?', 'numeric_input', '[]'::jsonb, '5', 'The vertical angle and zenith angle are complements: vertical angle = 90 - zenith = 90 - 85 = 5 degrees above horizontal.', 'easy', 'c1000002-0000-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000008', 'The two legs of a right triangle are 30.00 ft and 40.00 ft. What is the length of the hypotenuse?', 'numeric_input', '[]'::jsonb, '50', 'By the Pythagorean theorem, c = sqrt(30^2 + 40^2) = sqrt(900 + 1600) = sqrt(2500) = 50.00 ft. This is the classic 3-4-5 right triangle scaled by 10.', 'easy', 'c1000002-0000-0000-0000-000000000002', 'f3f20b2d-c28f-46d7-a20b-bea06201b1fc', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000009', 'You know two sides of a triangle and the angle included between them, and need the third side. Which law applies directly?', 'multiple_choice', '["The law of sines","The law of cosines","The Pythagorean theorem only","Heron''s formula"]'::jsonb, 'The law of cosines', 'Two sides and the included angle (SAS) is solved for the third side by the law of cosines: c^2 = a^2 + b^2 - 2ab cos(C). The law of sines cannot start an SAS problem because no side-angle pair is opposite each other.', 'medium', 'c1000002-0000-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000010', 'The ''ambiguous case'' that can yield two valid triangles arises when you know two sides and a non-included angle (SSA) and solve with the law of sines.', 'true_false', '["True","False"]'::jsonb, 'True', 'Because sin(theta) = sin(180 - theta), the SSA case can produce zero, one, or two geometrically valid triangles. You must check whether the supplementary angle also yields a valid triangle.', 'medium', 'c1000002-0000-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000011', 'In a triangle, a = 300 ft is opposite angle A = 40 degrees, and angle B = 60 degrees. Using the law of sines, side b is closest to:', 'multiple_choice', '["230 ft","404 ft","300 ft","467 ft"]'::jsonb, '404 ft', 'b = a x sin(B)/sin(A) = 300 x sin(60)/sin(40) = 300 x 0.8660/0.6428 = 404 ft. The side opposite the larger angle (60 > 40) must be longer than a, which it is.', 'hard', 'c1000002-0000-0000-0000-000000000002', '7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000012', 'In standard survey COGO, how are the departure (change in easting) and latitude (change in northing) computed from a line''s azimuth and length L?', 'multiple_choice', '["Departure = L cos(Az), latitude = L sin(Az)","Departure = L sin(Az), latitude = L cos(Az)","Departure = L tan(Az), latitude = L / cos(Az)","Departure = L / sin(Az), latitude = L / cos(Az)"]'::jsonb, 'Departure = L sin(Az), latitude = L cos(Az)', 'Because azimuth is measured clockwise from north, the east (departure) component uses sine and the north (latitude) component uses cosine: dE = L sin(Az), dN = L cos(Az).', 'medium', 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000013', 'To find the azimuth from point 1 to point 2 in survey COGO, which call of the two-argument arctangent is correct?', 'multiple_choice', '["atan2(dN, dE)","atan2(dE, dN)","atan(dN / dE) with no quadrant correction","acos(dE / dN)"]'::jsonb, 'atan2(dE, dN)', 'Survey azimuths are measured from north, so the easting difference is the first argument: Az = atan2(dE, dN). Add 360 degrees if the result is negative. The math convention atan2(y, x) measures from the x-axis and would swap the arguments.', 'hard', 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000014', 'Point A is (N 1000.00, E 1000.00) and point B is (N 1300.00, E 1400.00). What is the horizontal distance from A to B?', 'numeric_input', '[]'::jsonb, '500', 'dN = 300, dE = 400, so distance = hypot(400, 300) = sqrt(400^2 + 300^2) = sqrt(250000) = 500.00 ft. Another 3-4-5 triangle scaled by 100.', 'medium', 'c1000002-0000-0000-0000-000000000002', '8339b9ef-a60e-4fd7-9ffd-220e2250bb7e', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000015', 'An old deed calls a line 1000.00 varas. Using the Texas legal vara, what is this distance in feet?', 'numeric_input', '[]'::jsonb, '2777.78', 'The Texas legal vara is 33 1/3 inches = 2.7778 ft. So 1000 varas x 2.7778 = 2777.78 ft. Treating varas as feet or yards would introduce a large systematic scale error.', 'medium', 'c1000002-0000-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000016', 'How many feet are in one Gunter''s chain?', 'numeric_input', '[]'::jsonb, '66', 'One Gunter''s chain is 66 feet, divided into 100 links of 0.66 ft each. An acre equals 10 square chains (43,560 sq ft) and a mile is 80 chains.', 'easy', 'c1000002-0000-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000017', 'Why does the distinction between the U.S. survey foot and the international foot matter for State Plane coordinates?', 'multiple_choice', '["They differ by about 10 percent, so any distance is badly affected","They differ by about 2 parts per million, which becomes significant over the large coordinate values of state plane","Only the survey foot can be used for areas","There is no real difference; the terms are synonyms"]'::jsonb, 'They differ by about 2 parts per million, which becomes significant over the large coordinate values of state plane', 'The U.S. survey foot (1200/3937 m) is about 2 ppm longer than the international foot (0.3048 m). Over a state plane coordinate of several hundred thousand feet, that small ratio amounts to a foot or more, so the foot definition must be documented.', 'hard', 'c1000002-0000-0000-0000-000000000002', '068b86a9-cc98-457b-8479-2ab60d011ad1', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000018', 'A triangle has sides a = 50 ft and b = 80 ft with an included angle C = 90 degrees. Using A = 1/2 ab sin(C), what is its area in square feet?', 'numeric_input', '[]'::jsonb, '2000', 'A = 1/2 x 50 x 80 x sin(90) = 1/2 x 4000 x 1 = 2000 sq ft. With a 90-degree included angle the two sides are the legs, so this matches 1/2 base x height.', 'medium', 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000019', 'Which method computes a polygon''s area directly from the northing and easting of every corner?', 'multiple_choice', '["Heron''s formula","The trapezoidal rule","The shoelace (coordinate / DMD) formula","The law of sines"]'::jsonb, 'The shoelace (coordinate / DMD) formula', 'The shoelace formula, A = 1/2 |sum of (Xi Y(i+1) - X(i+1) Yi)|, equivalent to the double-meridian-distance method, gives area directly from coordinates. Heron''s needs side lengths; the trapezoidal rule needs offsets to an irregular boundary.', 'medium', 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000020', 'A coordinate computation gives a parcel area of 87,120 square feet. What is this in acres?', 'numeric_input', '[]'::jsonb, '2', 'Divide square feet by 43,560: 87,120 / 43,560 = 2.000 acres. One acre is 43,560 sq ft (or 10 square chains).', 'easy', 'c1000002-0000-0000-0000-000000000002', '392e4287-7043-44e7-8bc0-b81d423c933b', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0230-0000-0000-0000-000000000021', 'Why should a surveyor carry extra significant figures through intermediate computations and round only the final answer?', 'multiple_choice', '["To make the work look more precise than it is","Because premature rounding accumulates error that can shift the final reported value","Because calculators cannot handle decimals","It is not necessary; rounding at each step is fine"]'::jsonb, 'Because premature rounding accumulates error that can shift the final reported value', 'Rounding intermediate trig and distance values introduces small errors that compound across a multi-step computation, potentially shifting the reported coordinate or area. Keep full precision until the final reported figure.', 'medium', 'c1000002-0000-0000-0000-000000000002', '7669b3eb-ea77-478b-9d58-d2eff6eb4302', ARRAY['buildout','module-2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0260-0000-0000-0000-000000000001', 'A right triangle has legs measuring {{a:f2}} ft and {{b:f2}} ft. Using the Pythagorean theorem, what is the length of the hypotenuse, in feet?', 'numeric_input', '[]'::jsonb, '0', 'By the Pythagorean theorem, c = sqrt(a^2 + b^2) = sqrt({{a:f2}}^2 + {{b:f2}}^2) = {{_answer}} ft. The hypotenuse is always longer than either leg.', 'easy', 'c1000002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-2','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0250-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0260-0000-0000-0000-000000000002', 'From station B a surveyor measures the distances to two control points: a = {{a:f2}} ft and c = {{c:f2}} ft, with an included angle at B of {{B:f2}} degrees. Using the law of cosines, what is the distance b between the two control points, in feet?', 'numeric_input', '[]'::jsonb, '0', 'The law of cosines gives the side opposite the known included angle: b = sqrt(a^2 + c^2 - 2ac cos(B)) = sqrt({{a:f2}}^2 + {{c:f2}}^2 - 2({{a:f2}})({{c:f2}})cos({{B:f2}} deg)) = {{_answer}} ft.', 'medium', 'c1000002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-2','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0250-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0260-0000-0000-0000-000000000003', 'Point A is at (N {{n1:f2}}, E {{e1:f2}}) and point B is at (N {{n2:f2}}, E {{e2:f2}}). Using the inverse computation, what is the horizontal distance from A to B, in feet?', 'numeric_input', '[]'::jsonb, '0', 'The inverse distance is the hypotenuse of the dE-dN right triangle: distance = sqrt(dE^2 + dN^2) = hypot({{de:f2}}, {{dn:f2}}) = {{_answer}} ft.', 'medium', 'c1000002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-2','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0250-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0260-0000-0000-0000-000000000004', 'Point A is at (N {{n1:f2}}, E {{e1:f2}}) and point B is at (N {{n2:f2}}, E {{e2:f2}}). Using atan2(dE, dN), what is the azimuth from A to B, in decimal degrees (0 to 360, measured clockwise from north)?', 'numeric_input', '[]'::jsonb, '0', 'With both differences positive the line is in the NE quadrant, so Az = atan2(dE, dN) = atan2({{de:f2}}, {{dn:f2}}) = {{_answer}} degrees. Note that for survey azimuths from north, dE is the first argument and dN the second.', 'hard', 'c1000002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-2','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0250-0000-0000-0000-000000000004', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0260-0000-0000-0000-000000000005', 'A triangular parcel has corners A (N {{n1:f2}}, E {{e1:f2}}), B (N {{n2:f2}}, E {{e2:f2}}), and C (N {{n3:f2}}, E {{e3:f2}}). Using the shoelace (coordinate) formula, what is the enclosed area, in square feet?', 'numeric_input', '[]'::jsonb, '0', 'The shoelace formula sums the cross products of consecutive coordinates and halves the absolute value: A = 1/2 |sum| = {{_answer}} sq ft. Taking the absolute value removes any sign from the vertex ordering.', 'hard', 'c1000002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-2','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0250-0000-0000-0000-000000000005', 1);
