-- 338_buildout_m2.sql (GENERATED) — fill empty lessons for "Mathematics for Surveyors"
-- Module c1000002-0000-0000-0000-000000000002. Namespaced by tag 'buildout' / created_by 'buildout:m2' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='c1000002-0000-0000-0000-000000000002' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c1000002-0000-0000-0000-000000000002' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000002-0000-0000-0000-000000000002' AND created_by='buildout:m2';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Most field calculations reduce to solving a single equation for one unknown.','The sum of interior angles of an n-sided polygon is (n - 2) x 180 degrees.','Similar triangles share equal angles and proportional sides, the basis of stadia and scaling.']::text[], learning_objectives=ARRAY['Manipulate linear equations and solve for an unknown variable in surveying formulas.','Apply the Pythagorean theorem and basic geometry of triangles, circles, and polygons.','Use ratios, proportions, and the rules for similar triangles to scale measurements.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='02ce6947-ebfd-40ed-8ee9-30aae4331968';
DELETE FROM lesson_blocks WHERE lesson_id='02ce6947-ebfd-40ed-8ee9-30aae4331968';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['SOHCAHTOA: sine = opposite/hypotenuse, cosine = adjacent/hypotenuse, tangent = opposite/adjacent.','On the unit circle a point at angle theta has coordinates (cos theta, sin theta); signs change by quadrant.','The master identity sin^2 + cos^2 = 1 lets you find one function from another and check results.']::text[], learning_objectives=ARRAY['Define sine, cosine, and tangent from the right triangle and from the unit circle.','Convert between degrees, degrees-minutes-seconds, and radians.','Apply the Pythagorean and reciprocal identities to simplify and check trigonometric work.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='24f0890d-d4b8-4d6c-b287-009d76f7502d';
DELETE FROM lesson_blocks WHERE lesson_id='24f0890d-d4b8-4d6c-b287-009d76f7502d';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['A right triangle is fully solved from any one side plus one acute angle, or from any two sides.','Horizontal distance = slope x cos(vertical angle); vertical = slope x sin(vertical angle).','The missing leg or hypotenuse follows from the Pythagorean theorem when two sides are known.']::text[], learning_objectives=ARRAY['Solve a right triangle for any missing side or angle given sufficient data.','Reduce a slope distance to horizontal and vertical components using a zenith or vertical angle.','Apply right-triangle trigonometry to offsets, heights, and the missing-side Pythagorean problem.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='f3f20b2d-c28f-46d7-a20b-bea06201b1fc';
DELETE FROM lesson_blocks WHERE lesson_id='f3f20b2d-c28f-46d7-a20b-bea06201b1fc';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['An oblique triangle has no right angle and is solved with the law of sines or the law of cosines.','Law of sines: a/sin A = b/sin B = c/sin C; law of cosines: c^2 = a^2 + b^2 - 2ab cos C.','Use the law of cosines for SAS and SSS cases; the law of sines for ASA, AAS, and the ambiguous SSA case.']::text[], learning_objectives=ARRAY['Apply the law of sines to solve a triangle given two angles and a side, or two sides and a non-included angle.','Apply the law of cosines to solve a triangle given two sides and the included angle, or all three sides.','Recognize the ambiguous case of the law of sines and choose the correct triangle.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a';
DELETE FROM lesson_blocks WHERE lesson_id='7dbd1cd4-2b1b-4d8d-850a-9c338ac3587a';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['COGO works in a plane: each point has a northing (Y) and easting (X).','Forward: dE = L sin(Az), dN = L cos(Az). Inverse: distance = hypot(dE, dN), azimuth = atan2(dE, dN).','Intersections solve for a new point from two lines (bearings) or two distances (radii).']::text[], learning_objectives=ARRAY['Compute departure and latitude from a bearing/azimuth and distance, and the inverse.','Use the inverse to recover distance and azimuth between two known coordinates.','Understand the role of intersections (bearing-bearing, distance-distance) in locating points.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='8339b9ef-a60e-4fd7-9ffd-220e2250bb7e';
DELETE FROM lesson_blocks WHERE lesson_id='8339b9ef-a60e-4fd7-9ffd-220e2250bb7e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['1 chain = 66 feet = 100 links; 1 acre = 43,560 sq ft = 10 square chains.','The U.S. survey foot and international foot differ by 2 parts per million, which matters over long state-plane distances.','In Texas, 1 vara = 33 1/3 inches = 2.7778 feet (the Texas legal value); old grants are dimensioned in varas.']::text[], learning_objectives=ARRAY['Convert among feet, meters, chains, and varas using correct factors.','Distinguish the U.S. survey foot from the international foot and explain why it matters.','Apply the Texas vara correctly when retracing Spanish, Mexican, and Republic-era grants.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='068b86a9-cc98-457b-8479-2ab60d011ad1';
DELETE FROM lesson_blocks WHERE lesson_id='068b86a9-cc98-457b-8479-2ab60d011ad1';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Triangle area = 1/2 base x height = 1/2 ab sin(C) = Heron''s formula from three sides.','The trapezoidal rule sums averaged offset strips for irregular boundaries.','The shoelace formula computes any polygon''s area directly from its coordinates.']::text[], learning_objectives=ARRAY['Compute the area of a triangle by base-height, by two-sides-and-included-angle, and by Heron''s formula.','Apply the trapezoidal rule to areas bounded by an irregular line of offsets.','Compute polygon area from coordinates using the shoelace (cross-product) formula and convert to acres.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='392e4287-7043-44e7-8bc0-b81d423c933b';
DELETE FROM lesson_blocks WHERE lesson_id='392e4287-7043-44e7-8bc0-b81d423c933b';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Real problems chain several tools: reduce, inverse, then area, then convert.','Choosing the right formula starts with inventorying what is known (sides, angles, coordinates).','Round only at the end; premature rounding introduces avoidable error.']::text[], learning_objectives=ARRAY['Integrate trigonometry, COGO, and area methods to solve multi-step field problems.','Select the correct formula and unit conversion for a given data set.','Carry full precision through intermediate steps and round only the final answer.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7669b3eb-ea77-478b-9d58-d2eff6eb4302';
DELETE FROM lesson_blocks WHERE lesson_id='7669b3eb-ea77-478b-9d58-d2eff6eb4302';
  'eeee0250-0000-0000-0000-000000000001', 'Right-triangle missing side (hypotenuse) via Pythagorean theorem', 'Right-triangle missing side (hypotenuse) via Pythagorean theorem', 'Surveying Mathematics — Right Triangles', 'Pythagorean theorem', 'numeric_input', 'easy', 'A right triangle has legs measuring {{a:f2}} ft and {{b:f2}} ft. Using the Pythagorean theorem, what is the length of the hypotenuse, in feet?', 'hypot(a, b)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"a","type":"float","min":25,"max":300,"decimals":2},{"name":"b","type":"float","min":25,"max":300,"decimals":2}]'::jsonb, '[{"name":"aSq","formula":"a*a"},{"name":"bSq","formula":"b*b"}]'::jsonb, '[{"step_number":1,"title":"Square each leg","formula":"a^2 and b^2","calculation_template":"{{a:f2}}^2 = {{aSq:f2}}; {{b:f2}}^2 = {{bSq:f2}}"},{"step_number":2,"title":"Add and take the square root","result_template":"sqrt({{aSq:f2}} + {{bSq:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'By the Pythagorean theorem, c = sqrt(a^2 + b^2) = sqrt({{a:f2}}^2 + {{b:f2}}^2) = {{_answer}} ft. The hypotenuse is always longer than either leg.', 'c1000002-0000-0000-0000-000000000002', ARRAY['buildout','module-2','practice']::text[], true, 'buildout:m2');
  'eeee0250-0000-0000-0000-000000000002', 'Law of cosines for a triangle side (SAS)', 'Law of cosines for a triangle side (SAS)', 'Surveying Mathematics — Oblique Triangles', 'Law of cosines', 'numeric_input', 'medium', 'From station B a surveyor measures the distances to two control points: a = {{a:f2}} ft and c = {{c:f2}} ft, with an included angle at B of {{B:f2}} degrees. Using the law of cosines, what is the distance b between the two control points, in feet?', 'sqrt(a*a + c*c - 2*a*c*cos(toRad(B)))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"a","type":"float","min":200,"max":600,"decimals":2},{"name":"c","type":"float","min":200,"max":600,"decimals":2},{"name":"B","type":"float","min":35,"max":130,"decimals":2}]'::jsonb, '[{"name":"bSq","formula":"a*a + c*c - 2*a*c*cos(toRad(B))"}]'::jsonb, '[{"step_number":1,"title":"Apply the law of cosines","formula":"b^2 = a^2 + c^2 - 2ac cos(B)","calculation_template":"b^2 = {{a:f2}}^2 + {{c:f2}}^2 - 2({{a:f2}})({{c:f2}})cos({{B:f2}}) = {{bSq:f2}}"},{"step_number":2,"title":"Take the square root","result_template":"b = sqrt({{bSq:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The law of cosines gives the side opposite the known included angle: b = sqrt(a^2 + c^2 - 2ac cos(B)) = sqrt({{a:f2}}^2 + {{c:f2}}^2 - 2({{a:f2}})({{c:f2}})cos({{B:f2}} deg)) = {{_answer}} ft.', 'c1000002-0000-0000-0000-000000000002', ARRAY['buildout','module-2','practice']::text[], true, 'buildout:m2');
  'eeee0250-0000-0000-0000-000000000003', 'Inverse: distance between two coordinates', 'Inverse: distance between two coordinates', 'Surveying Mathematics — Coordinate Geometry', 'Inverse computation', 'numeric_input', 'medium', 'Point A is at (N {{n1:f2}}, E {{e1:f2}}) and point B is at (N {{n2:f2}}, E {{e2:f2}}). Using the inverse computation, what is the horizontal distance from A to B, in feet?', 'hypot(de, dn)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"n1","type":"float","min":4000,"max":6000,"decimals":2},{"name":"e1","type":"float","min":4000,"max":6000,"decimals":2},{"name":"dn","type":"float","min":-800,"max":800,"decimals":2},{"name":"de","type":"float","min":-800,"max":800,"decimals":2}]'::jsonb, '[{"name":"n2","formula":"n1 + dn"},{"name":"e2","formula":"e1 + de"}]'::jsonb, '[{"step_number":1,"title":"Coordinate differences","formula":"dE = E2 - E1; dN = N2 - N1","calculation_template":"dE = {{e2:f2}} - {{e1:f2}} = {{de:f2}}; dN = {{n2:f2}} - {{n1:f2}} = {{dn:f2}}"},{"step_number":2,"title":"Distance by Pythagorean theorem","result_template":"distance = hypot({{de:f2}}, {{dn:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The inverse distance is the hypotenuse of the dE-dN right triangle: distance = sqrt(dE^2 + dN^2) = hypot({{de:f2}}, {{dn:f2}}) = {{_answer}} ft.', 'c1000002-0000-0000-0000-000000000002', ARRAY['buildout','module-2','practice']::text[], true, 'buildout:m2');
  'eeee0250-0000-0000-0000-000000000004', 'Inverse: azimuth between two coordinates', 'Inverse: azimuth between two coordinates', 'Surveying Mathematics — Coordinate Geometry', 'Inverse azimuth', 'numeric_input', 'hard', 'Point A is at (N {{n1:f2}}, E {{e1:f2}}) and point B is at (N {{n2:f2}}, E {{e2:f2}}). Using atan2(dE, dN), what is the azimuth from A to B, in decimal degrees (0 to 360, measured clockwise from north)?', 'toDeg(atan2(de, dn))', '{"decimals":4,"unit":"deg","tolerance":0.01}', '[{"name":"n1","type":"float","min":4000,"max":6000,"decimals":2},{"name":"e1","type":"float","min":4000,"max":6000,"decimals":2},{"name":"dn","type":"float","min":80,"max":800,"decimals":2},{"name":"de","type":"float","min":80,"max":800,"decimals":2}]'::jsonb, '[{"name":"n2","formula":"n1 + dn"},{"name":"e2","formula":"e1 + de"},{"name":"azRad","formula":"atan2(de, dn)"}]'::jsonb, '[{"step_number":1,"title":"Coordinate differences","formula":"dE = E2 - E1; dN = N2 - N1","calculation_template":"dE = {{de:f2}}; dN = {{dn:f2}} (both positive, so the line runs into the NE quadrant)"},{"step_number":2,"title":"Two-argument arctangent","result_template":"Az = atan2({{de:f2}}, {{dn:f2}}) = {{_answer}} degrees"}]'::jsonb, '{"method":"none"}'::jsonb, 'With both differences positive the line is in the NE quadrant, so Az = atan2(dE, dN) = atan2({{de:f2}}, {{dn:f2}}) = {{_answer}} degrees. Note that for survey azimuths from north, dE is the first argument and dN the second.', 'c1000002-0000-0000-0000-000000000002', ARRAY['buildout','module-2','practice']::text[], true, 'buildout:m2');
  'eeee0250-0000-0000-0000-000000000005', 'Shoelace area of a triangle from three coordinates', 'Shoelace area of a triangle from three coordinates', 'Surveying Mathematics — Area Computation', 'Shoelace / coordinate area', 'numeric_input', 'hard', 'A triangular parcel has corners A (N {{n1:f2}}, E {{e1:f2}}), B (N {{n2:f2}}, E {{e2:f2}}), and C (N {{n3:f2}}, E {{e3:f2}}). Using the shoelace (coordinate) formula, what is the enclosed area, in square feet?', 'abs(e1*n2 - e2*n1 + e2*n3 - e3*n2 + e3*n1 - e1*n3)/2', '{"decimals":1,"unit":"sq ft","tolerance":1}', '[{"name":"e1","type":"float","min":4900,"max":5100,"decimals":2},{"name":"n1","type":"float","min":4900,"max":5100,"decimals":2},{"name":"e2","type":"float","min":5200,"max":5500,"decimals":2},{"name":"n2","type":"float","min":5100,"max":5400,"decimals":2},{"name":"e3","type":"float","min":5200,"max":5500,"decimals":2},{"name":"n3","type":"float","min":4600,"max":4900,"decimals":2}]'::jsonb, '[{"name":"cross","formula":"e1*n2 - e2*n1 + e2*n3 - e3*n2 + e3*n1 - e1*n3"}]'::jsonb, '[{"step_number":1,"title":"Sum the cross products","formula":"sum of (Xi Y(i+1) - X(i+1) Yi)","calculation_template":"({{e1:f2}})({{n2:f2}}) - ({{e2:f2}})({{n1:f2}}) + ({{e2:f2}})({{n3:f2}}) - ({{e3:f2}})({{n2:f2}}) + ({{e3:f2}})({{n1:f2}}) - ({{e1:f2}})({{n3:f2}}) = {{cross:f1}}"},{"step_number":2,"title":"Half the absolute value","result_template":"area = |{{cross:f1}}| / 2 = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The shoelace formula sums the cross products of consecutive coordinates and halves the absolute value: A = 1/2 |sum| = {{_answer}} sq ft. Taking the absolute value removes any sign from the vertex ordering.', 'c1000002-0000-0000-0000-000000000002', ARRAY['buildout','module-2','practice']::text[], true, 'buildout:m2');
COMMIT;
SELECT 'm2 Mathematics for Surveyors: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000002-0000-0000-0000-000000000002') || ' blocks.' AS status;